// v17: trailing per T2 runner dopo partial TP — attivazione a 2R, si stringe progressivamente
double GetTrailDistanceT2(string symbol, double profit_R) {
   double atr_h4 = GetATR(symbol, PERIOD_H4, 14, 1);
   double atr_d1 = GetATR(symbol, PERIOD_D1, 14, 1);
   if(profit_R < 5.0)  return (atr_h4 > 0 ? atr_h4 * 1.5 : 0.0020);
   if(profit_R < 10.0) return (atr_d1 > 0 ? atr_d1 * 1.0 : 0.0040);
   if(profit_R < 20.0) return (atr_d1 > 0 ? atr_d1 * 0.75 : 0.0030);
   return (atr_d1 > 0 ? atr_d1 * 0.5 : 0.0025);  // >20R: trail strettissimo
}

void ManageTrailingStructural(string symbol, int direction) {

   double pipSize = SymbolInfoDouble(symbol, SYMBOL_POINT) * 10;

   for(int i = 0; i < PositionsTotal(); i++) {

      ulong ticket = PositionGetTicket(i);
      if(ticket == 0) continue;
      if(PositionGetString(POSITION_SYMBOL) != symbol) continue;

      string comment = PositionGetString(POSITION_COMMENT);
      bool isTT = (StringFind(comment, "TT") == 0 || StringFind(comment, "T_TRAIL") == 0);
      bool isT2 = (StringFind(comment, "T2") == 0);
      if(!isTT && !isT2) continue;

      double currentSL  = PositionGetDouble(POSITION_SL);
      double entryPrice = PositionGetDouble(POSITION_PRICE_OPEN);
      double price      = PositionGetDouble(POSITION_PRICE_CURRENT);
      double atr_entry  = GetATR(symbol, PERIOD_M15, 14, 2);
      if(atr_entry <= 0) atr_entry = GetATR(symbol, PERIOD_M15, 14, 1);

      // Calcola profit_R corrente
      double excursion  = (direction == 1) ? price - entryPrice : entryPrice - price;
      double profit_R   = (atr_entry > 0) ? excursion / atr_entry : 0;

      // v17: T2 attiva trailing solo da 2R (evita whipsaw zona 1-2R)
      if(isT2 && !isTT && profit_R < 2.0) continue;

      // v17: T2 usa trail progressivo più stretto ad alto R, TT usa trail standard
      double trail_dist = isTT ? GetTrailDistanceV16(symbol, profit_R)
                                : GetTrailDistanceT2(symbol, profit_R);

